🏦 TBANK API: Получает последние 3 оплаченных накладных

📋 ENDPOINT:
GET /v1/consignments?limit=3&status=paid

📋 ОЖИДАЕМЫЙ ОТВЕТ:
{
  "consignments": [
    {
      "id": "...",
      "customer": { "inn": "...", "name": "..." },
      "delivery_address": "...",
      "items": [...]
    }
  ]
}

parameters.jsCode:
// Парсинг накладных из Т-Банка
const response = $input.item.json;
console.log('[TBank] Raw API response:', JSON.stringify(response, null, 2));
const consignments = response.consignments || response.data?.consignments || response || [];
const chatId = $('Telegram Command Trigger').item.json.message?.chat?.id;

// Если накладных нет
if (!Array.isArray(consignments) || consignments.length === 0) {
  return {
    json: {
      chatId: chatId,
      hasConsignments: false,
      message: '❌ Нет накладных для обработки'
    }
  };
}

// Парсим каждую накладную
const parsedConsignments = consignments.slice(0, 3).map((c, index) => {
  // Извлекаем данные клиента
  const customer = c.customer || c.recipient || {};
  const inn = customer.inn || customer.tax_id || 'Не указан';
  const companyName = customer.name || customer.company_name || customer.company || 'Не указан';

  // Извлекаем адрес
  const address = c.delivery_address || c.address || c.to_location?.address || 'Не указан';

  // Извлекаем товары
  const items = c.items || c.products || c.order_lines || [];
  const productItems = items.filter(item => {
    const name = (item.name || item.title || '').toLowerCase();
    return !name.includes('доставка') && !name.includes('курьер') && !name.includes('пвз');
  });

  // Определяем тип доставки
  const deliveryItem = items.find(item => {
    const name = (item.name || item.title || '').toLowerCase();
    return name.includes('доставка') || name.includes('курьер') || name.includes('пвз') || name.includes('сдэк');
  });

  const deliveryName = deliveryItem?.name || deliveryItem?.title || '';
  const isCourier = deliveryName.toLowerCase().includes('курьер') || 
                    deliveryName.toLowerCase().includes('до адреса') ||
                    deliveryName.toLowerCase().includes('до двери');
  const isPVZ = deliveryName.toLowerCase().includes('пвз') || 
                deliveryName.toLowerCase().includes('сдэк') ||
                deliveryName.toLowerCase().includes('пункт');

  const deliveryType = isCourier ? 'courier' : (isPVZ ? 'pvz' : 'unknown');
  const deliveryLabel = isCourier ? '🚚 Курьер' : (isPVZ ? '📦 ПВЗ СДЭК' : '❓ Не определен');

  // Форматируем товары
  const productsText = productItems.map(p => {
    const name = p.name || p.title || 'Товар';
    const qty = p.quantity || p.count || 1;
    return `${name} × ${qty} шт`;
  }).join(', ') || 'Нет товаров';

  return {
    index: index + 1,
    id: c.id || c.consignment_id || `cons-${index}`,
    inn: inn,
    companyName: companyName,
    address: address,
    products: productsText,
    productItems: productItems,
    deliveryType: deliveryType,
    deliveryLabel: deliveryLabel,
    rawData: c
  };
});

// Формируем сообщение для Telegram
let messageText = '📋 *Последние накладные из Т-Банка:*\n\n';

parsedConsignments.forEach((c, idx) => {
  messageText += `*${c.index}.* ИНН: \`${c.inn}\` | ${c.companyName}\n`;
  messageText += `   📍 ${c.address}\n`;
  messageText += `   🛒 ${c.products}\n`;
  messageText += `   ${c.deliveryLabel}\n\n`;
});

messageText += '\n_Выберите номер накладной для создания заказа:_';

// Сохраняем накладные в staticData для использования после callback
if (!$workflow.staticData) $workflow.staticData = {};
$workflow.staticData.consignments = parsedConsignments;
$workflow.staticData.chatId = chatId;

return {
  json: {
    chatId: chatId,
    hasConsignments: true,
    message: messageText,
    consignments: parsedConsignments,
    consignmentCount: parsedConsignments.length
  }
};

