// Обработка callback выбора накладной
const callback = $input.item.json.callback_query || $input.item.json;
const callbackData = callback.data || '';
const chatId = callback.message?.chat?.id || callback.from?.id;

console.log('[Callback] Received:', callbackData);

// Парсим callback data
const [action, indexStr] = callbackData.split(':');
const selectedIndex = parseInt(indexStr, 10);

// Получаем сохраненные накладные из staticData
const consignments = $workflow.staticData?.consignments || [];
const selectedConsignment = consignments[selectedIndex];

if (!selectedConsignment) {
  return {
    json: {
      error: true,
      message: '❌ Накладная не найдена. Попробуйте снова с /orders',
      chatId: chatId,
      callbackId: callback.id
    }
  };
}

// Сохраняем выбранную накладную и переходим к запросу телефона
$workflow.staticData.selectedConsignment = selectedConsignment;
$workflow.staticData.dialogState = 'awaiting_phone';
$workflow.staticData.chatId = chatId;

console.log('[Callback] Selected consignment:', selectedConsignment.id);

return {
  json: {
    error: false,
    selectedConsignment: selectedConsignment,
    chatId: chatId,
    callbackId: callback.id,
    nextStep: 'ask_phone'
  }
};

// Обработка текстового ответа (телефон или email)
const message = $input.item.json.message;
const text = message?.text || '';
const chatId = message?.chat?.id;

// Получаем состояние диалога
const dialogState = $workflow.staticData?.dialogState || 'idle';
const selectedConsignment = $workflow.staticData?.selectedConsignment;

console.log('[Dialog] State:', dialogState, 'Text:', text);

// Если нет активного диалога - игнорируем
if (dialogState === 'idle' || !selectedConsignment) {
  return {
    json: {
      ignore: true,
      reason: 'No active dialog'
    }
  };
}

// Обработка телефона
if (dialogState === 'awaiting_phone') {
  // Валидация телефона (простая)
  const phoneClean = text.replace(/[^0-9+]/g, '');
  if (phoneClean.length < 10) {
    return {
      json: {
        error: true,
        message: '❌ Неверный формат телефона. Введите телефон в формате +79991234567',
        chatId: chatId,
        state: 'awaiting_phone'
      }
    };
  }

  // Сохраняем телефон и переходим к запросу email
  $workflow.staticData.phone = phoneClean;
  $workflow.staticData.dialogState = 'awaiting_email';

  return {
    json: {
      error: false,
      phone: phoneClean,
      chatId: chatId,
      state: 'awaiting_email',
      nextStep: 'ask_email'
    }
  };
}

// Обработка email
if (dialogState === 'awaiting_email') {
  // Валидация email (простая)
  const emailPattern = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!emailPattern.test(text)) {
    return {
      json: {
        error: true,
        message: '❌ Неверный формат email. Введите email в формате example@domain.com',
        chatId: chatId,
        state: 'awaiting_email'
      }
    };
  }

  // Сохраняем email и переходим к созданию заказа
  const phone = $workflow.staticData.phone;
  $workflow.staticData.email = text;
  $workflow.staticData.dialogState = 'creating_order';

  return {
    json: {
      error: false,
      phone: phone,
      email: text,
      chatId: chatId,
      selectedConsignment: selectedConsignment,
      state: 'creating_order',
      nextStep: 'create_order'
    }
  };
}

return {
  json: {
    ignore: true,
    reason: 'Unknown dialog state: ' + dialogState
  }
};

// Проверяем тип доставки и подготавливаем данные для создания заказа
const data = $input.item.json;
const consignment = data.selectedConsignment;

console.log('[Create Order] Delivery type:', consignment.deliveryType);

// Определяем нужно ли искать ПВЗ
const needPVZLookup = consignment.deliveryType === 'pvz';

return {
  json: {
    ...data,
    needPVZLookup: needPVZLookup,
    isCourier: consignment.deliveryType === 'courier',
    address: consignment.address,
    products: consignment.productItems || []
  }
};

// Обработка результата геокодирования
const geocodeResult = $input.item.json;
const prevData = $('Check Delivery Type').item.json;

let coordinates = null;
if (Array.isArray(geocodeResult) && geocodeResult.length > 0) {
  coordinates = {
    lat: parseFloat(geocodeResult[0].lat),
    lon: parseFloat(geocodeResult[0].lon)
  };
}

// Извлекаем город из адреса для поиска ПВЗ
const address = prevData.address || '';
const cityMatch = address.match(/(?:г\.?\s*|город\s+)([^,]+)/i);
const city = cityMatch ? cityMatch[1].trim() : address.split(',')[0].trim();

return {
  json: {
    ...prevData,
    coordinates: coordinates,
    city: city,
    geocodingSuccess: !!coordinates
  }
};

// Поиск ближайшего ПВЗ
const pvzList = $input.item.json;
const prevData = $('Process Geocode Result').item.json;
const coordinates = prevData.coordinates;

let nearestPVZ = null;
let minDistance = Infinity;

if (Array.isArray(pvzList) && pvzList.length > 0) {
  // Если есть координаты - ищем ближайший
  if (coordinates) {
    pvzList.forEach(pvz => {
      if (pvz.location?.latitude && pvz.location?.longitude) {
        const pvzLat = parseFloat(pvz.location.latitude);
        const pvzLon = parseFloat(pvz.location.longitude);

        // Формула Haversine для расчета расстояния
        const R = 6371;
        const dLat = (pvzLat - coordinates.lat) * Math.PI / 180;
        const dLon = (pvzLon - coordinates.lon) * Math.PI / 180;
        const a = Math.sin(dLat/2) * Math.sin(dLat/2) +
                  Math.cos(coordinates.lat * Math.PI / 180) * 
                  Math.cos(pvzLat * Math.PI / 180) *
                  Math.sin(dLon/2) * Math.sin(dLon/2);
        const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
        const distance = R * c;

        if (distance < minDistance) {
          minDistance = distance;
          nearestPVZ = {
            code: pvz.code,
            name: pvz.name || 'ПВЗ СДЭК',
            address: pvz.location?.address || pvz.address || '',
            city: pvz.location?.city || prevData.city,
            distance: distance.toFixed(2) + ' км'
          };
        }
      }
    });
  }

  // Если координат нет или ПВЗ не найден - берем первый
  if (!nearestPVZ) {
    const pvz = pvzList[0];
    nearestPVZ = {
      code: pvz.code,
      name: pvz.name || 'ПВЗ СДЭК',
      address: pvz.location?.address || pvz.address || '',
      city: pvz.location?.city || prevData.city,
      distance: 'N/A'
    };
  }
}

return {
  json: {
    ...prevData,
    pvz: nearestPVZ,
    pvzFound: !!nearestPVZ,
    deliveryAddress: nearestPVZ ? nearestPVZ.address : prevData.address
  }
};

// Подготовка данных для курьерской доставки
const data = $input.item.json;

return {
  json: {
    ...data,
    pvz: null,
    pvzFound: false,
    deliveryAddress: data.address,
    deliveryType: 'courier'
  }
};

