parameters.jsCode:
// Извлечение данных созданного заказа
const response = $input.item.json;
const order = response.order || response;
const prevData = $('Merge Delivery Data').item.json;

const orderId = order.id || order.number || 'N/A';
const orderNumber = order.number || order.id || 'N/A';

// Очищаем состояние диалога
$workflow.staticData.dialogState = 'idle';
$workflow.staticData.selectedConsignment = null;
$workflow.staticData.phone = null;
$workflow.staticData.email = null;

return {
  json: {
    success: true,
    orderId: orderId,
    orderNumber: orderNumber,
    chatId: prevData.chatId,
    consignment: prevData.selectedConsignment,
    deliveryType: prevData.pvz ? 'pvz' : 'courier',
    pvz: prevData.pvz,
    phone: prevData.phone,
    email: prevData.email
  }
};

// Обработка ошибок
const error = $input.item.json.error || 'Unknown error';
const chatId = $workflow.staticData?.chatId || $env.TG_CHAT_ID;

// Очищаем состояние диалога при ошибке
$workflow.staticData.dialogState = 'idle';
$workflow.staticData.selectedConsignment = null;
$workflow.staticData.phone = null;
$workflow.staticData.email = null;

console.error('[Error Handler]', error);

return {
  json: {
    error: error.toString(),
    chatId: chatId,
    timestamp: new Date().toISOString()
  }
};

